INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Blueprint markup and versioning$q$, $q$Field teams can mark up drawings on mobile or web and automatically sync changes with full version history.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Hyperlinked sheet sets$q$, $q$Drawings are cross-linked so users can jump directly from a callout to the referenced detail or sheet.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$RFIs and submittals tracking$q$, $q$Requests for information and submittal packages are logged, routed and tied to specific drawing locations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Punch lists and field reports$q$, $q$Teams can create, assign and close out punch-list items and daily field reports from the jobsite.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Offline mobile access$q$, $q$The mobile app supports offline viewing and markup, syncing automatically once a connection is restored.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Autodesk Construction Cloud integration$q$, $q$Data flows into the broader Autodesk Build and Autodesk Construction Cloud ecosystem, including BIM 360 tools.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Purpose-built for field crews who need reliable offline access to current drawings on a jobsite$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Deep integration with Autodesk's broader Construction Cloud and BIM tools after the acquisition$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Long track record and strong brand recognition in the AEC industry$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Hyperlinked drawing sets make navigating large sheet sets faster than paper$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$No longer sold as a standalone product, which can confuse buyers searching for 'PlanGrid' pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Pricing is custom and quote-based, making cost comparison harder than tools with public pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Migration into Autodesk Build means some legacy PlanGrid workflows and UI have changed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Steeper learning curve and higher cost than lightweight construction apps aimed at small contractors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Is PlanGrid still available to buy?$q$, $q$PlanGrid is no longer sold as an independent product to new customers. Its blueprint and field-management technology is now part of Autodesk Build (renamed Forma Build in 2026) within Autodesk Construction Cloud.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Who founded PlanGrid?$q$, $q$PlanGrid was founded in 2011 in San Francisco by Tracy Young, Ralph Gootee, Ryan Sutton-Gee, Kenny Stone and Antoine Hersen.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$When did Autodesk acquire PlanGrid?$q$, $q$Autodesk announced the acquisition in November 2018 and completed it in December 2018 for USD 875 million.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$How much does PlanGrid/Autodesk Build cost?$q$, $q$Pricing is custom and quote-based through Autodesk sales; legacy standalone PlanGrid plans previously ranged from about USD 39 to USD 139 per user per month depending on the tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$What is PlanGrid used for?$q$, $q$It is used for managing construction blueprints, markups, RFIs, submittals, punch lists and daily field reports on commercial and residential construction projects.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$What are the main alternatives to PlanGrid?$q$, $q$Common alternatives include Procore, Fieldwire, and Buildertrend.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Does PlanGrid work offline?$q$, $q$Yes, the mobile app supports offline viewing and markup of drawings, syncing changes automatically once connectivity returns.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Jobsite blueprint access$q$, $q$Field crews pull up the latest drawing revisions on mobile devices, even without an internet connection, to avoid working from outdated paper plans.$q$, $q$General contractors and site supervisors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$RFI and submittal tracking$q$, $q$Project managers log, route and close out RFIs and submittals directly against specific drawing locations for a clear audit trail.$q$, $q$Project managers and architects$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Punch list close-out$q$, $q$Teams create and assign punch-list items tied to drawing locations and photos, then track them to completion before project handover.$q$, $q$Owners, contractors and quality control teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Autodesk Build (formerly PlanGrid)$q$, $q$Custom (contact sales)$q$, $q$Annual or monthly, per-user subscription$q$, NULL, $q$["Blueprint markup and version history","RFIs, submittals and punch lists","Field reports and photo documentation","Integration with Autodesk Construction Cloud and BIM 360"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PlanGrid began in 2011 as an independent construction field management startup focused on replacing paper blueprints with a searchable, markup-friendly mobile and web app. Contractors, architects and owners used it to view large-format drawings on tablets and phones, mark up changes in the field, and keep every stakeholder working from the current version of a drawing set.$q$, $q$Autodesk acquired PlanGrid in December 2018 for USD 875 million, one of the largest deals in construction software history at the time. Rather than operate PlanGrid as a separate product indefinitely, Autodesk merged its field-collaboration capabilities into Autodesk Construction Cloud, and specifically into Autodesk Build (rebranded Forma Build in 2026), so the PlanGrid name today mostly describes the underlying technology and mobile app rather than a stand-alone purchasable plan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Even inside Autodesk Build, the PlanGrid-derived toolset centers on digitized drawing sheets with version history, markup and hyperlinking, so field teams can pull up the latest revision of any sheet and see how it connects to related drawings, specs and RFIs without hunting through paper sets.$q$, $q$Field reporting tools cover punch lists, RFIs, submittals, daily logs and photo documentation, all tied back to specific sheet locations, which gives project managers and owners a traceable record of what was built, what changed, and who signed off on it.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PlanGrid is no longer sold as an independent subscription to new customers; its capabilities are packaged inside Autodesk Build (Forma Build) within Autodesk Construction Cloud, which uses custom, quote-based pricing driven by user counts, modules and project scale.$q$, $q$Historically, standalone PlanGrid pricing followed named tiers (often referenced as Nailgun, Dozer and Crane) priced per user per month with limits on the number of drawing sheets storable per project, with higher tiers unlocking unlimited sheets and more advanced field-management modules.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Customer health scoring$q$, $q$Configurable health scores combine usage, support and engagement data to flag at-risk or high-opportunity accounts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$No-code data modeling$q$, $q$Teams can define custom objects and fields to match their own customer, product and revenue structure.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Automated playbooks$q$, $q$Trigger-based workflows automate tasks, alerts and outreach tied to account milestones or risk signals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Revenue and renewal tracking$q$, $q$Tracks ARR, renewals, upsell and expansion opportunities alongside customer health data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Customer portals$q$, $q$Branded portals let customers collaborate on shared plans, tasks and milestones with their vendor.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$AI-assisted insights$q$, $q$AI features help surface churn risk, renewal forecasts and account opportunities from usage and engagement data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$PSA and services module$q$, $q$Professional services automation tools support project and services delivery tracking for customer-facing teams.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Highly flexible, no-code data model adapts to different business structures without custom development$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Combines customer success, light CRM and PSA in one platform, reducing tool sprawl$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Strong automation and playbook capabilities for scaling customer success operations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Backed by a bootstrapped, profitable history before raising funding, suggesting strong product-market fit$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$No public pricing, making it hard to budget or compare without a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Flexible data model can require significant setup and configuration time to get right$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Feature breadth (CS plus CRM plus PSA plus AI) may be more than smaller teams need$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Enterprise-oriented pricing can be costly for very small customer success teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$What is Planhat used for?$q$, $q$Planhat is used by customer success, product and revenue teams to track customer health, automate renewal and onboarding workflows, and manage the overall customer lifecycle.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Who founded Planhat and when?$q$, $q$Planhat was founded in 2014 in Stockholm, Sweden by Kaveh Rostampor and Niklas Skog.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$How much does Planhat cost?$q$, $q$Planhat uses custom, quote-based pricing driven by the number of managed customer accounts and enabled modules; there is no published per-seat price list.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Is Planhat a CRM?$q$, $q$Planhat includes lightweight CRM-style account management features, but it is primarily built as a customer success and revenue platform rather than a full sales CRM replacement.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$What companies compete with Planhat?$q$, $q$Common competitors include Gainsight, ChurnZero, Totango and Vitally.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Does Planhat use AI?$q$, $q$Yes, Planhat offers AI-assisted features for surfacing churn risk, renewal forecasts and account opportunities, with an upgraded AI platform available as an add-on.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Is Planhat suitable for small businesses?$q$, $q$Planhat is generally positioned toward mid-market and enterprise B2B companies with dedicated customer success teams rather than very small businesses.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Churn and renewal risk management$q$, $q$Customer success teams monitor health scores and usage trends to identify at-risk accounts before renewal.$q$, $q$Customer success managers and CS leadership$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Onboarding and expansion playbooks$q$, $q$Teams automate onboarding checklists and expansion triggers based on product usage and account milestones.$q$, $q$Customer success and account management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Cross-functional customer visibility$q$, $q$Sales, support and product teams share one view of account health, usage and revenue instead of siloed spreadsheets.$q$, $q$Revenue operations and B2B SaaS leadership$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$Planhat (all tiers)$q$, $q$Custom (contact sales)$q$, $q$Annual contract, quote-based$q$, NULL, $q$["Customer health scoring and dashboards","No-code data modeling","Automated playbooks and workflows","Optional CRM, PSA, AI and advanced portal add-ons"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Planhat was founded in 2014 in Stockholm by Kaveh Rostampor and Niklas Skog to help subscription businesses track customer health and reduce churn. The founders bootstrapped the company for about seven years before raising outside funding, building a product used by customer success, product and revenue teams at B2B software companies.$q$, $q$Today Planhat markets itself as a 'customer platform' spanning customer success management (CSM), a lightweight CRM, professional services automation and AI-assisted workflows, aiming to be a single system of record for how a company manages its existing customer base.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Planhat's data model is flexible and no-code: teams can define their own objects (accounts, licenses, products, usage events) rather than being locked into a fixed schema, then build custom health scores and dashboards on top of that data.$q$, $q$Automation features include playbooks that trigger tasks, alerts or outreach based on usage drops, renewal dates or health-score changes, along with AI features aimed at surfacing churn risk, expansion opportunities and renewal forecasts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('599548f2-9d79-4758-9183-d5c016b8b2a6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Planhat does not publish fixed per-seat pricing. Instead it uses a quote-based model that is primarily driven by the number of active customer accounts a company manages and which modules (CS, CRM, PSA, AI, advanced portals) are enabled, rather than a strict per-user seat count.$q$, $q$Add-ons such as an upgraded AI platform, advanced service and PSA tools, email marketing, and advanced customer portals are priced separately, and enterprise buyers typically work with Planhat's sales team on implementation and onboarding as part of the contract.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Real-time Kanban boards$q$, $q$Boards, lists and cards update live for all connected users without needing to refresh the page.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Self-hosted deployment$q$, $q$Runs on your own server or cloud environment via Docker, keeping full control over data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Unlimited boards and cards$q$, $q$The Community Edition places no artificial limits on the number of boards or cards a team can create.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Multi-language interface$q$, $q$The interface has been translated into 35-plus languages by the community.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Pro Edition scalability$q$, $q$A paid Pro tier adds higher scalability, advanced features and premium support for larger teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Managed cloud or self-hosted Pro$q$, $q$Pro Edition customers can choose between self-managing infrastructure or a fully managed cloud deployment.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Free to self-host with no per-user fees for the Community Edition$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Familiar, Trello-like interface with a low learning curve$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Real-time collaboration and unlimited boards and cards$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Full data ownership, appealing to privacy- and compliance-conscious teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Active open development community with frequent updates and many translations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Self-hosting requires basic server or Docker administration skills$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$The Fair Use License is not an OSI-approved open-source license and restricts reselling Planka as a hosted service$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Pro Edition pricing is not fully transparent on the public website$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Lacks some advanced automation and reporting features found in larger commercial PM tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Is Planka really free?$q$, $q$Yes, the Community Edition is free to self-host, though a paid Pro Edition with added scalability and support is also available.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Is Planka open source?$q$, $q$Planka's source code is publicly available on GitHub, but it is distributed under a fair-code 'Fair Use License' rather than a traditional OSI-approved open-source license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$How do I install Planka?$q$, $q$Planka is typically deployed via Docker on your own server or cloud provider; PLANKA also offers a paid installation service if you want it set up for you.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Who makes Planka?$q$, $q$Planka is developed by PLANKA Software GmbH, based in Kempten, Germany.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$What is Planka's main alternative?$q$, $q$Trello is the closest hosted alternative, while Wekan is a fully open-source, self-hosted alternative in the same category.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Can I use Planka to host boards for other companies as a service?$q$, $q$No, the Fair Use License prohibits operating Planka as a hosted service for third parties without a commercial Pro license.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Does Planka support multiple languages?$q$, $q$Yes, its interface has been translated into more than 35 languages through community contributions.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Privacy-conscious project tracking$q$, $q$Teams that need to keep task data on their own infrastructure self-host Planka instead of using a third-party SaaS Kanban tool.$q$, $q$Privacy-focused teams and regulated organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Small team Kanban workflow$q$, $q$Startups and small teams use Planka as a free Trello alternative to organize sprints, backlogs and to-do lists.$q$, $q$Startups and small development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Internal agency task boards$q$, $q$Agencies run Planka internally to track client work and deliverables without paying per-seat SaaS fees.$q$, $q$Agencies and internal operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Community Edition$q$, $q$Free$q$, $q$N/A (self-hosted)$q$, NULL, $q$["Unlimited boards and cards","Real-time collaboration","Docker-based self-hosting","Multi-language interface"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$Pro Edition$q$, $q$Custom (contact sales)$q$, $q$Subscription, self-hosted or managed cloud$q$, NULL, $q$["Higher scalability","Advanced professional features","Premium support","Optional fully managed cloud hosting"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Planka is a Kanban-style project and task management tool designed to be self-hosted, giving teams a Trello-like board experience while keeping full ownership of their data. The project has been developed publicly on GitHub since 2019 by PLANKA Software GmbH, based in Kempten, Germany, and has grown to more than 11,000 GitHub stars.$q$, $q$The Community Edition is source-available and free to run on your own infrastructure, typically via Docker. In 2025 the company launched a Pro Edition for teams that need greater scalability, additional professional features, and premium support, offered either self-hosted or as a managed cloud service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Planka supports unlimited boards, lists and cards with real-time updates, so changes made by one team member appear instantly for everyone else viewing the same board, similar to the live-collaboration feel of hosted tools like Trello.$q$, $q$Because it is self-hosted, teams get full control over where their data lives, which matters for organizations with data residency, privacy or compliance requirements. The interface has also been translated into more than 35 languages through community contributions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community Edition is completely free to self-host under Planka's fair-code 'Fair Use License,' which allows personal, internal, non-profit and educational use but restricts reselling Planka as a hosted service to third parties without a commercial license.$q$, $q$The newer Pro Edition adds scalability and support features and is available self-hosted or fully managed; PLANKA also offers a paid installation and configuration service, starting at roughly EUR 469 plus VAT, for teams that want assistance deploying it on their own server or cloud environment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bfc32b77-2902-4a87-8ab8-27743eb3989b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Visual grid planner$q$, $q$Drag-and-drop scheduling lets users preview how an Instagram feed will look before publishing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Multi-platform scheduling$q$, $q$Schedules posts to Instagram, Facebook, TikTok, LinkedIn, Pinterest, YouTube Shorts and Threads.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$AI captions and hashtags$q$, $q$AI tools generate captions and suggest relevant hashtags to speed up content creation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Team collaboration$q$, $q$Approval flows, team chat and shareable client links support agencies and multi-person teams on higher tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Analytics and strategy builder$q$, $q$Reporting tools and a strategy builder help track performance and plan content themes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Multi-brand management$q$, $q$Higher plans support managing multiple brands or client accounts from one account.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Strong visual grid-planning tools, especially for Instagram-first brands$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Supports a wide range of platforms including TikTok, LinkedIn, Pinterest and YouTube Shorts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Usable free plan for testing before committing to a paid tier$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Team and agency features like approval flows and client links on higher plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Backed by Linktree's resources following the 2024 acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Free plan is limited to Instagram scheduling only, capping its usefulness for multi-platform creators$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Higher tiers needed to unlock multi-brand and team collaboration features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$AI credits are capped on lower tiers, limiting how much AI content generation is available$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Smaller ecosystem and integration library compared to larger competitors like Hootsuite$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$What is Plann used for?$q$, $q$Plann is used to visually plan, schedule and analyze social media content across platforms like Instagram, TikTok, Facebook, LinkedIn, Pinterest and YouTube Shorts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Who owns Plann now?$q$, $q$Plann was acquired by Linktree in August 2024 and now operates as part of Linktree's product suite.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Does Plann have a free plan?$q$, $q$Yes, Plann offers a free plan limited to one brand, one user and Instagram-only scheduling with capped monthly posts and AI credits.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$How much does Plann cost?$q$, $q$Paid plans start at roughly USD 12.50 per month billed annually for the Power User tier, rising to roughly USD 62.50 per month for the Grow tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Who founded Plann?$q$, $q$Plann was founded in 2016 in Sydney, Australia by Christy Laurence.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$What platforms does Plann support?$q$, $q$Plann supports Instagram, Facebook, TikTok, LinkedIn, Pinterest, YouTube Shorts and Threads.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$What are the best alternatives to Plann?$q$, $q$Popular alternatives include Later, Buffer and Hootsuite.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Instagram grid planning$q$, $q$Creators and brands visually arrange posts on a grid to preview aesthetic flow before publishing.$q$, $q$Content creators and influencers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Multi-platform content scheduling$q$, $q$Small businesses schedule and manage posts across Instagram, TikTok, Facebook and LinkedIn from one calendar.$q$, $q$Small business owners and marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Agency client management$q$, $q$Social media agencies manage multiple client brands, approval workflows and shareable content calendars in one account.$q$, $q$Social media agencies and freelance managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 brand, 1 user","Instagram-only scheduling","Up to 5 video posts per month","30 monthly AI credits"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Power User$q$, $q$$12.50/month (billed annually) or $15/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["1 brand, 1 user","Unlimited scheduling across all platforms","AI suite and hashtag suggestions","Strategy builder"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Build$q$, $q$$25/month (billed annually) or $30/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["2 brands, 2 users","Team chat and approval flows","Shareable client links","Collaboration tools for multiple accounts"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$Grow$q$, $q$$62.50/month (billed annually) or $75/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["5 brands, 4 users","Advanced analytics","Advanced integrations","Expanded team collaboration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Plann was founded in 2016 in Sydney by Christy Laurence to help brands and creators visually plan their Instagram grids before posting, rather than scheduling content blindly. The tool grew into a broader multi-platform scheduler used by more than three million brands worldwide.$q$, $q$In August 2024, Plann was acquired by Linktree, the Melbourne-based link-in-bio company, with the entire Plann team joining Linktree. The acquisition combined Linktree's link-in-bio distribution with Plann's content planning and scheduling tools under one company.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Plann's core feature is visual content planning: users drag and drop posts onto a grid or calendar to preview how an Instagram feed will look before anything goes live, alongside AI-generated captions and hashtag suggestions to speed up content creation.$q$, $q$Beyond Instagram, Plann schedules content to Facebook, TikTok, LinkedIn, Pinterest, YouTube Shorts and Threads, and includes team collaboration features like approval workflows, shareable client links and analytics on paid plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83b2c83b-806d-4059-8675-877f2b95353d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Plann offers a free plan limited to one brand, one user, a capped number of AI credits, and Instagram-only scheduling with a maximum of five video posts per month.$q$, $q$Paid plans scale from Power User (one brand, one user) through Build (two brands, two users, team features) to Grow (five brands, four users, advanced analytics), priced from roughly USD 12.50 to USD 62.50 per month when billed annually, with all paid tiers covering the full range of supported platforms.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Text-to-diagram syntax$q$, $q$Diagrams are written as plain text and rendered automatically, making them easy to version and diff.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Broad UML diagram support$q$, $q$Covers sequence, class, use case, activity, component, state and deployment diagrams.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Extended diagram types$q$, $q$Also supports ArchiMate, BPMN-style flows, C4 model diagrams, Gantt charts and mind maps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$JSON and YAML visualization$q$, $q$Can render structured JSON and YAML data directly as visual diagrams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Editor and CI integrations$q$, $q$Plugins exist for VS Code, IntelliJ, Confluence and many static site generators and CI pipelines.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Self-hostable server$q$, $q$Can be run locally, as a self-hosted PlantUML Server, or accessed via public rendering servers.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Completely free and open source with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Diagrams-as-code approach fits naturally into version control and documentation-as-code workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Extremely broad diagram type support beyond just UML$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Large ecosystem of editor, wiki and CI integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Long-running, mature project with an active community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Text-based syntax has a learning curve compared to drag-and-drop diagram tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Fine-grained visual styling and layout control is more limited than dedicated design tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Relies on Java and, for some diagram types, Graphviz, which adds setup steps for self-hosting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$No official commercial support plans, so enterprise users rely on community help or third-party vendors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Is PlantUML free?$q$, $q$Yes, PlantUML is completely free and open source, distributed under the GPL license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Who created PlantUML?$q$, $q$PlantUML was created by developer Arnaud Roques and first released in 2009.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$What diagram types does PlantUML support?$q$, $q$It supports UML diagrams like sequence, class, use case, activity and state diagrams, plus ArchiMate, BPMN-style flows, C4 diagrams, Gantt charts, mind maps and more.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Can I self-host PlantUML?$q$, $q$Yes, PlantUML can be run locally, as a self-hosted PlantUML Server, or accessed through public rendering servers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$What is the difference between PlantUML and Mermaid?$q$, $q$Both are text-to-diagram tools, but Mermaid renders natively inside GitHub and many Markdown viewers by default, while PlantUML supports a broader range of diagram types and typically requires a rendering server or plugin.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Does PlantUML require Graphviz?$q$, $q$Some PlantUML diagram types rely on the Graphviz layout engine for rendering, so self-hosted setups often need Graphviz installed.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Can PlantUML diagrams be embedded in documentation?$q$, $q$Yes, PlantUML integrates with tools like Confluence, VS Code, IntelliJ and many documentation and static site generators.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Software architecture documentation$q$, $q$Engineering teams document system architecture and sequence flows as version-controlled text alongside their code.$q$, $q$Software engineers and architects$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$API and onboarding documentation$q$, $q$Technical writers embed generated diagrams directly into Markdown docs and wikis to explain system behavior.$q$, $q$Technical writers and developer relations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$Automated diagram generation in CI$q$, $q$Teams generate up-to-date architecture or dependency diagrams automatically as part of build pipelines.$q$, $q$DevOps and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$PlantUML$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full UML and extended diagram support","Self-hosted or public server rendering","GPL open-source license","Editor, wiki and CI integrations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PlantUML was first released in 2009 by developer Arnaud Roques as a way to generate UML diagrams directly from plain-text descriptions rather than manual drag-and-drop editors. It has since become one of the most widely adopted diagrams-as-code tools in software development.$q$, $q$As an open-source project distributed under the GPL license, PlantUML has no company, funding, or commercial pricing behind it. It is maintained by its original author alongside a community of contributors on GitHub, and is free to download, self-host, or use through public and private PlantUML servers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PlantUML supports the full range of classic UML diagram types, including sequence, class, use case, activity, component, state and deployment diagrams, all defined with a concise, human-readable text syntax.$q$, $q$Beyond UML, it supports ArchiMate, BPMN-style diagrams, C4 model diagrams, Gantt charts, mind maps, wireframes, entity-relationship diagrams and network diagrams, plus direct visualization of JSON and YAML data, making it useful well beyond strict UML modeling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PlantUML is entirely free and open source under the GPL license. There are no paid tiers, subscriptions, or feature gates for the core tool itself.$q$, $q$Costs, if any, come from optional infrastructure choices, such as running a self-hosted PlantUML server at scale or paying for third-party plugins, hosting, or documentation platforms that embed PlantUML rendering, rather than from PlantUML itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ea83f533-2784-47e9-b55f-e37f270b013d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Strategic portfolio management$q$, $q$Aligns top-down strategic objectives with the projects, programs and investments funded to deliver them.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Resource and capacity planning$q$, $q$Tracks resource allocation and capacity across projects and programs to avoid overcommitment.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Agile program management$q$, $q$Supports scaled agile frameworks and cross-team program coordination alongside traditional PPM.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Value stream management$q$, $q$Connects delivery tools like Jira and Azure DevOps to visualize flow and bottlenecks across the software delivery pipeline.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Product portfolio management$q$, $q$Helps product organizations prioritize and track investment across a portfolio of products and features.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Reporting and dashboards$q$, $q$Provides executive-level dashboards and reporting across portfolios, programs and resource utilization.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Extremely broad functional coverage spanning strategy, portfolio, program and delivery-level management$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Long track record and deep enterprise PPM experience dating back to 1989$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Strong value stream management and toolchain integration capabilities via the Tasktop acquisition$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Suited to complex, multi-team, multi-tool enterprise environments$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$No public pricing, requiring a sales conversation for even a rough cost estimate$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Complexity and breadth can be overkill for small or mid-sized teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Product line assembled through many acquisitions can feel fragmented across modules$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Steeper implementation and onboarding effort compared to lightweight PM tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$What does Planview do?$q$, $q$Planview provides enterprise software for strategic portfolio management, project and program management, resource planning, and value stream management.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$When was Planview founded?$q$, $q$Planview was founded in 1989 in Austin, Texas by Patrick Durbin.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$How much does Planview cost?$q$, $q$Planview uses custom, quote-based enterprise pricing negotiated with its sales team based on modules, users and deployment scale; it does not publish fixed prices.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Who owns Planview?$q$, $q$Planview is owned by private equity firms TPG and TA Associates, following a 2020 acquisition from Thoma Bravo valued at USD 1.6 billion, with Thoma Bravo retaining a minority stake.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$What is Planview AdaptiveWork?$q$, $q$Planview AdaptiveWork is the product line formed from Planview's 2021 acquisitions of Clarizen and Changepoint, focused on work and project management.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Who are Planview's main competitors?$q$, $q$Key competitors include Broadcom Clarity PPM, monday.com, Smartsheet, and Jira Align.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Is Planview suitable for small businesses?$q$, $q$Planview is primarily built for large enterprises and PMOs managing complex, multi-team portfolios rather than small businesses.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Enterprise portfolio prioritization$q$, $q$PMOs use Planview to align strategic objectives with funded projects and track portfolio-level investment.$q$, $q$PMO leaders and enterprise executives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Software delivery value stream visibility$q$, $q$IT leaders connect Jira, Azure DevOps and other tools through Planview to see flow and bottlenecks across delivery pipelines.$q$, $q$IT and engineering leadership$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Resource capacity planning across programs$q$, $q$Program managers track resource allocation across multiple concurrent projects to prevent overcommitment.$q$, $q$Program and resource managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Planview Enterprise Suite$q$, $q$Custom (contact sales)$q$, $q$Annual enterprise contract$q$, NULL, $q$["Strategic portfolio management","Resource and capacity planning","Agile program management","Value stream management and toolchain integrations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Planview was founded in 1989 in Austin, Texas by Patrick Durbin and grew into one of the longest-running vendors in the project and portfolio management (PPM) space, launching its flagship web-based Planview Enterprise platform in 1997.$q$, $q$Over the past decade Planview expanded significantly through acquisitions, including LeanKit, Clarizen, Changepoint, Tasktop and Plutora, broadening its portfolio from classic top-down PPM into agile program management, value stream management and toolchain integration for software delivery.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Planview's product suite spans strategic portfolio management, resource and capacity planning, project and program management, agile program management, and product portfolio management, letting large organizations plan work at multiple altitudes from executive strategy down to team-level delivery.$q$, $q$Its value stream management capabilities, strengthened by the 2022 Tasktop acquisition, connect tools like Jira, Azure DevOps, ServiceNow and GitHub into a single pipeline view, giving leadership visibility into software delivery flow, bottlenecks and cycle time across many disconnected teams and tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Planview does not publish standard pricing for its products. Costs are negotiated directly with its sales team and are based on the specific modules selected, number of users, and deployment scale, typical of enterprise PPM software.$q$, $q$Because Planview targets large enterprises and PMOs rather than small teams, contracts are generally structured as multi-year enterprise agreements rather than simple monthly per-seat subscriptions.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Visual drag-and-drop canvas$q$, $q$Designers and marketers build and edit UI visually without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Codebase integration$q$, $q$Generates production-ready code that plugs directly into existing React and Next.js projects.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Headless CMS$q$, $q$Includes a built-in content management system that can be used with or without the visual builder.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$AI-assisted design$q$, $q$AI tools help generate and edit content and components within the visual builder.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$A/B testing and scheduled content$q$, $q$Higher-tier plans support content experimentation and scheduled publishing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Component and data binding$q$, $q$Visual elements can bind to real application data and logic defined by developers.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Generates clean, framework-native code instead of locking content into a proprietary platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Lets marketers and designers edit pages visually without waiting on engineering$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Usable free tier with unlimited projects for getting started$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Flexible enough to work as a headless CMS alone or a full visual builder embedded in code$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Smaller company and team size than larger no-code competitors like Webflow$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Requires some developer setup to integrate deeply into an existing codebase$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Additional collaborators cost extra on Pro and Scale tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Learning curve for teams unfamiliar with headless, code-integrated visual builders$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$What is Plasmic used for?$q$, $q$Plasmic is used to visually build and edit web pages and UI components that generate production-ready code, typically integrated into an existing React or Next.js codebase.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Who founded Plasmic?$q$, $q$Plasmic was founded in 2019 in San Francisco by CEO Yang Zhang and CTO Chung Wu.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Is Plasmic free?$q$, $q$Yes, Plasmic offers a free tier with unlimited projects and a headless CMS for up to three collaborators; paid plans start at around USD 39 per month billed yearly.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Does Plasmic work with React?$q$, $q$Yes, Plasmic is designed to integrate directly into React and Next.js codebases, generating code that developers can review and extend.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Is Plasmic a no-code tool?$q$, $q$Plasmic is a visual, low-code/no-code builder aimed at letting non-developers edit UI, while still producing real code that developers control.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$What are Plasmic's main competitors?$q$, $q$Key competitors include Webflow, Builder.io and Framer.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Does Plasmic have a CMS?$q$, $q$Yes, Plasmic includes a built-in headless CMS that can be used independently of the visual page builder.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Marketer-editable marketing pages$q$, $q$Marketing teams build and update landing pages visually while the generated code stays inside the engineering team's repository.$q$, $q$Marketing teams and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Design-to-code handoff$q$, $q$Designers prototype and build UI components visually that developers then wire into application logic.$q$, $q$Product designers and frontend engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Headless content management$q$, $q$Teams use Plasmic's CMS to manage structured content consumed by a custom-built frontend.$q$, $q$Content teams and engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Free$q$, $q$$0/month$q$, $q$N/A$q$, NULL, $q$["Unlimited projects","Headless CMS","Up to 3 collaborators","Community forum support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Starter$q$, $q$$39/month (billed yearly)$q$, $q$Annual$q$, NULL, $q$["Everything in Free","Remove Plasmic badge","Custom favicon","AI support chat"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Pro$q$, $q$$103/month (billed yearly)$q$, $q$Annual$q$, NULL, $q$["Everything in Starter","4-10 collaborators","Priority support","Unlimited Plasmic AI access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Scale$q$, $q$$399/month (billed yearly)$q$, $q$Annual$q$, NULL, $q$["Everything in Pro","8-30 collaborators","Content creator mode","A/B testing and scheduled content"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Custom collaborators and integrations","Custom roles and permissions","SSO and domain capture","Whitelabeling, embedding and SLAs"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Plasmic was founded in 2019 in San Francisco by CEO Yang Zhang, a former Google Research and Microsoft Research engineer with a PhD from MIT, and CTO Chung Wu. The company set out to solve a common tension between marketing and engineering teams: marketers want to edit pages visually, while developers want clean, maintainable code.$q$, $q$Plasmic's answer is a headless visual builder that plugs directly into an existing codebase, most commonly React or Next.js projects, so non-engineers can build and edit UI visually while the underlying code stays framework-native and under version control rather than trapped inside a proprietary platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The visual canvas supports drag-and-drop page and component design, with the ability to bind design elements to real application data and logic defined by developers, so visual edits stay connected to live functionality rather than becoming static mockups.$q$, $q$Plasmic also ships a built-in headless CMS, AI-assisted design and content tools, and support for A/B testing and scheduled content publishing on higher tiers, making it usable both as a marketing site builder and as an internal visual editing layer for product teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62f1f869-8400-4cf4-bb92-4a6aa2ab0719', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Plasmic's Free tier includes unlimited projects and a headless CMS for up to three collaborators, making it accessible for individuals and small projects to get started at no cost.$q$, $q$Paid tiers scale from Starter (around USD 39 per month billed yearly) through Pro (around USD 103 per month) to Scale (around USD 399 per month), adding more collaborators, AI access, A/B testing and content scheduling, with custom Enterprise pricing for SSO, whitelabeling and dedicated support.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Cookieless tracking$q$, $q$Collects traffic data without cookies, so most sites do not need a cookie consent banner for analytics.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Single-page dashboard$q$, $q$Presents key metrics like visitors, referrers, top pages and bounce rate on one simple, fast-loading dashboard.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Open-source and self-hostable$q$, $q$Fully open source under AGPLv3, with the option to self-host instead of using the managed cloud service.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$GDPR and CCPA compliant by design$q$, $q$Collects no personally identifiable information and processes data entirely within the EU.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Pageview-based pricing$q$, $q$Cloud plans are priced by monthly pageview volume rather than per-seat licensing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Goals, funnels and revenue attribution$q$, $q$Tracks conversion goals, multi-step funnels and revenue attribution on higher-tier plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Stats API and integrations$q$, $q$Provides a Stats API and a Looker Studio connector for pulling analytics data into other tools.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Strong privacy focus with no cookies or personal data collection$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Lightweight, fast-loading tracking script compared to larger analytics suites$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Simple, single-page dashboard that is easy for non-analysts to read$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Open source with a free self-hosting option for full data control$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Transparent, pageview-based pricing rather than opaque enterprise quotes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Fewer advanced segmentation and behavioral analysis features than Google Analytics$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Self-hosting requires ongoing server maintenance and updates$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Higher-tier features like funnels and revenue attribution require the pricier Business plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Smaller ecosystem of third-party integrations than more established analytics platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Is Plausible Analytics really cookieless?$q$, $q$Yes, Plausible does not use cookies or collect personally identifiable information to track website visitors.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Is Plausible open source?$q$, $q$Yes, Plausible Analytics is open source under the GNU Affero General Public License v3 (AGPLv3), and it can be self-hosted for free.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$How much does Plausible cost?$q$, $q$Cloud pricing starts at USD 9 per month for the Starter plan covering up to 10,000 monthly pageviews, with Growth and Business plans starting at USD 14 and USD 19 per month respectively.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Who founded Plausible Analytics?$q$, $q$Plausible was founded by Uku Taht in December 2018, with Marko Saric joining in 2020 to lead marketing and communications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Where is Plausible based?$q$, $q$Plausible Insights OU is headquartered in Tartu, Estonia, and all data is hosted and processed within the EU.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Does Plausible require a cookie consent banner?$q$, $q$Because Plausible does not use cookies or collect personal data, most sites using it do not need to show a cookie consent banner under common GDPR interpretations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$What are the main alternatives to Plausible?$q$, $q$Common alternatives include Google Analytics, Fathom Analytics, Simple Analytics and Matomo.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Can I self-host Plausible for free?$q$, $q$Yes, because it is open source under AGPLv3, Plausible can be self-hosted at no license cost, though you are responsible for server maintenance.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$GDPR-friendly website analytics$q$, $q$Businesses in the EU and privacy-regulated industries use Plausible to track traffic without cookie banners or personal data collection.$q$, $q$EU businesses and privacy-conscious companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Lightweight traffic tracking for developers$q$, $q$Developers and indie makers add a small, fast script to track visitors without slowing down page load times.$q$, $q$Developers and indie makers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Self-hosted analytics for data control$q$, $q$Organizations self-host Plausible on their own infrastructure to keep full ownership of visitor data.$q$, $q$IT and security-conscious organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Starter$q$, $q$$9/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 10,000 monthly pageviews","1 site","3 years data retention","Email and Slack reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Growth$q$, $q$$14/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 3 sites","3 team members","Shared links and embedded dashboards","Team management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Business$q$, $q$$19/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 10 sites","10 team members","5 years data retention","Stats API, funnels and revenue attribution"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["10+ sites and team members","SSO and managed proxy","Raw data exports","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Plausible Analytics was started by Uku Taht in December 2018 as a response to what its founders saw as web analytics tools that had drifted from their original purpose of simply understanding site traffic into invasive, ad-driven surveillance of visitors. Paid subscriptions launched in 2019, and Marko Saric joined in 2020 to help lead growth and communications.$q$, $q$The company, Plausible Insights OU, is based in Tartu, Estonia, operates as a small, self-funded, profitable team of about 10 people, and has deliberately avoided outside venture funding, relying entirely on subscription revenue from its hosted product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Plausible tracks essential website metrics such as visitors, page views, referral sources, top pages, bounce rate and device type, all shown on a single, simple dashboard, without using cookies, fingerprinting, or any form of cross-site tracking.$q$, $q$Because it collects no personal data, sites using Plausible generally do not need to show a cookie consent banner under GDPR in most interpretations, which is one of its biggest practical draws for businesses trying to simplify privacy compliance while still getting reliable traffic analytics.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Plausible's hosted cloud product is priced by monthly pageviews rather than seats: Starter begins at USD 9 per month for up to 10,000 monthly pageviews, Growth begins at USD 14 per month with support for more sites and team members, and Business begins at USD 19 per month with custom properties, a Stats API, funnels and revenue attribution.$q$, $q$Because the software is open source under the AGPLv3 license, organizations that prefer not to pay a subscription can self-host Plausible on their own infrastructure at no license cost, trading the convenience of the managed cloud service for the effort of running and maintaining it themselves.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4ad6bb35-29e1-42bd-9183-39a59570aee8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
