-- в”Ђв”Ђ PlanGrid в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$PlanGrid is a cloud and mobile app for construction blueprint management, field collaboration, punch lists and RFIs, founded in 2011 in San Francisco and acquired by Autodesk in 2018 for USD 875 million.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact Autodesk sales)$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Part of Autodesk, Inc. (13,000+ employees); PlanGrid itself had about 400 employees at the time of its 2018 acquisition$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA (now part of Autodesk, headquartered in San Rafael, California)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PlanGrid Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PlanGrid (now Autodesk Build) construction field management software: blueprint markup, RFIs, punch lists, pricing, features and top alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PlanGrid is a construction field management platform built around digitized blueprints, mobile markup, RFIs (requests for information), punch lists, and daily field reports for architecture, engineering and construction (AEC) teams. It was founded in 2011 in San Francisco by Tracy Young, Ralph Gootee, Ryan Sutton-Gee, Kenny Stone and Antoine Hersen, and grew to roughly 400 employees, 12,000 customers and 120,000 paid users by the time Autodesk announced its acquisition of the company for USD 875 million in November 2018, with the deal closing in December 2018. Since the acquisition, PlanGrid's blueprint and field-collaboration technology has been folded into Autodesk Construction Cloud, and specifically into Autodesk Build (renamed Forma Build as part of Autodesk's 2026 rebrand of its construction portfolio), meaning PlanGrid is no longer sold as a fully standalone product to new customers; its capabilities now ship as part of the broader Autodesk Build subscription alongside BIM 360 field-management tools. Historically, PlanGrid used tiered per-user subscription pricing (commonly referenced as Nailgun, Dozer and Crane plans ranging from roughly USD 39 to USD 139 per user per month depending on sheet-storage limits), but current pricing for the merged Autodesk Build product is quote-based and depends on modules, project volume and user count. PlanGrid's key differentiator was always its offline-capable mobile app for viewing and marking up large-format construction drawings directly on the jobsite, with automatic version syncing once connectivity returned, plus hyperlinked sheet sets that let field crews jump between related drawings instantly. The product targets general contractors, subcontractors, architects and owners who need a single source of truth for as-built drawings, RFIs, submittals and punch-list tracking across a project's lifecycle. Its main competitors in construction field management include Procore, Fieldwire, Buildertrend, and the wider Autodesk Construction Cloud suite it was absorbed into. For SEO and directory purposes, PlanGrid remains one of the most-searched legacy brand names in construction tech, even though prospective buyers today are effectively evaluating Autodesk Build/Forma Build rather than a separately purchasable PlanGrid subscription.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9b3f0303-3e4e-44b8-b85b-8e246173d906';

