-- в”Ђв”Ђ plausible в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Plausible Analytics is an open-source, privacy-friendly, cookieless web analytics platform founded in Estonia in 2018, offering a lightweight alternative to Google Analytics without tracking personal data.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$$9/month (Starter plan); free if self-hosted$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Approximately 10 employees$q$, company_size),
  headquarters = COALESCE($q$Tartu, Estonia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Plausible Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Plausible Analytics: open-source, cookieless web analytics with no personal data tracking. Pricing plans, features and alternatives to Google Analytics.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Plausible Analytics is an open-source, privacy-focused web analytics platform built as a lightweight, cookieless alternative to Google Analytics. It was founded by Uku Taht, who started the project in December 2018 and launched paid subscriptions in 2019, with Marko Saric joining in 2020 to lead marketing and communications; the company, legally registered as Plausible Insights OU, is headquartered in Tartu, Estonia, and operates as a small, self-funded, profitable team of around 10 people with no outside venture investors. Plausible's core differentiator is privacy: it does not use cookies, does not collect or store any personally identifiable information, and does not track users across websites, which lets sites using it avoid cookie consent banners in many jurisdictions while still complying with GDPR and CCPA; all data is hosted and processed within the EU. The product is fully open source, licensed under the GNU Affero General Public License v3 (AGPLv3), and can be either self-hosted for free or run as a managed cloud SaaS. Plausible's cloud pricing is based on monthly pageviews rather than per-seat licensing: the Starter plan begins at USD 9 per month for up to 10,000 monthly pageviews with a single site and three years of data retention, the Growth plan begins at USD 14 per month and adds multiple sites and team members, and the Business plan begins at USD 19 per month and adds custom properties, the Stats API, funnels, revenue attribution and a Looker Studio connector, with all tiers scaling in price as pageview volume grows and custom Enterprise pricing available for sites with 10 million-plus monthly visitors. The platform targets developers, indie hackers, privacy-conscious businesses, and organizations in regulated industries that want simple, GDPR-friendly traffic analytics without the complexity, cookie banners, or data-privacy concerns of Google Analytics. Reported customers include Basecamp, Ghost, Hugging Face, MongoDB, the Python Software Foundation and Harvard University. Its main competitors in the privacy-focused analytics category include Fathom Analytics, Simple Analytics, Matomo, and Umami, alongside Google Analytics as the dominant incumbent it positions itself against.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4ad6bb35-29e1-42bd-9183-39a59570aee8';

